window.OPTIMIZATION_SCRIPT={GENETIC:{START:()=>`Welcome to the Genetic Algorithm! We're going to evolve a population of random strings to match our target. It's survival of the fittest in action!`,NEW_GENERATION:(e,t)=>`Generation ${e} is here. Our champion has a fitness of ${Math.round(t*100)}%. Let's see if we can do better!`,SELECTION:()=>`Selecting the strongest candidates. These 'elite' strings will pass their traits to the next generation.`,CROSSOVER:()=>`Time for crossover! We're mixing the genetic code of two parents to create offspring with hopefully the best of both worlds.`,MUTATION:()=>`A little bit of mutation! Sometimes a random change helps us discover a better solution that wasn't in the original pool.`,SUCCESS:e=>`Evolution complete! After ${e} generations, we've finally reached our target. Nature finds a way!`},ANNEALING:{START:()=>`Welcome to Simulated Annealing. We're solving the Traveling Salesman Problem! We'll start with a hot temperature, allowing us to explore many paths, even bad ones.`,ITERATION:(e,t)=>`Current temperature is ${e.toFixed(2)}. The total path length is ${Math.round(t)}. We're cooling down and narrowing our search.`,BETTER_FOUND:()=>`Found a shorter path! We're definitely heading in the right direction.`,WORSE_ACCEPTED:()=>`This path is longer, but we'll take it! High temperatures allow us to jump out of local traps to find even better paths later.`,STUCK:()=>`It's getting cold. We're now only accepting improvements as we settle into the best path we've found.`,SUCCESS:e=>`Annealing finished! The metal has cooled into a strong, short path with a total length of ${Math.round(e)}. Optimization complete!`}};